var RECS={gemini:[["gemini-2.5-flash-lite","Recomendado · mais cota no grátis (15/min, 1000/dia)"],["gemini-2.5-flash","Equilibrado · esperto e ainda no grátis"],["gemini-flash-latest","Sempre o Flash mais novo do Google · grátis"]],anthropic:[["claude-3-5-haiku-latest","Recomendado · rápido e barato"],["claude-sonnet-4-5","O mais inteligente"]],openai:[["gpt-4o-mini","Recomendado · barato e bom"],["gpt-4o","O mais inteligente"]],ollama:[]};
