function iaKeyCheck(){var pv=document.getElementById("ia-prov").value;var k=(document.getElementById("ia-key").value||"").trim();var min=IAMIN[pv]!=null?IAMIN[pv]:20;var ok=k.length>=min;var conn=IACONN&&pv===IAPROV_CONN;var bc=document.getElementById("btn-conn"),df=document.getElementById("btn-disc-flow");if(conn&&!k.length){if(df)df.style.display="";if(bc)bc.style.display="none";}else{if(df)df.style.display="none";if(bc){bc.style.display="";bc.disabled=!ok;}}var st=document.getElementById("ia-st");if(st&&st.style.color===""){if(!k.length){st.textContent="";}else if(!ok){st.textContent="faltam "+(min-k.length)+" caracteres";}else{st.textContent="chave ok ✔";}}}
function markModel(mod){var mi=document.getElementById("ia-modelo");if(mi)mi.value=mod||"";document.querySelectorAll("#ia-recs .rec").forEach(function(c){var b=c.querySelector("b");var nm=b?b.textContent.replace("\u2b50","").trim():"";c.classList.toggle("sel",nm===mod);});}
function selProv(p){var sel=document.getElementById("ia-prov");if(sel)sel.value=p;document.querySelectorAll(".provcard").forEach(function(c){c.classList.toggle("sel",c.getAttribute("data-p")===p);});iaProvCh();var sk=document.getElementById("step-key");if(sk)sk.style.display="";var conn=IACONN&&p===IAPROV_CONN;var k=document.getElementById("ia-key");if(k){k.value="";k.placeholder=conn?("\u2713 chave j\u00e1 conectada no "+(PNOME[p]||p)+" \u2014 cole outra s\u00f3 se quiser trocar"):"cole a chave da sua LLM";}var st=document.getElementById("ia-st");if(st){if(conn){st.textContent="\u2705 j\u00e1 conectado no "+(PNOME[p]||p)+" \u2014 s\u00f3 troque o modelo e salve";st.style.color="#1faa59";}else{st.textContent="";st.style.color="";}}var sm=document.getElementById("step-model");if(conn){if(sm)sm.style.display="";renderRecs();markModel(IAMOD_CONN);}else{if(sm)sm.style.display="none";var rc=document.getElementById("ia-recs");if(rc){rc.style.display="none";rc.innerHTML="";}}iaKeyCheck();}
function setModelo(m,el){var e=document.getElementById("ia-modelo");if(e)e.value=m;document.querySelectorAll("#ia-recs .rec").forEach(function(c){c.classList.remove("sel");});if(el)el.classList.add("sel");toast("Modelo: "+m);}
function renderRecs(){var p=document.getElementById("ia-prov").value;var box=document.getElementById("ia-recs");if(!box)return;var list=RECS[p]||[];if(!list.length){box.style.display="none";box.innerHTML="";return;}box.style.display="";box.innerHTML='<div class="muted" style="font-size:12px;margin:2px 0 6px">&#128161; <b>Escolha um modelo</b> (toque). A IA precisa raciocinar bem, mas gasta pouco &mdash; o <b>recomendado</b> &eacute; o melhor equil&iacute;brio:</div><div class="recrow">'+list.map(function(m,i){return '<div class="rec'+(i===0?" sel":"")+'" onclick="setModelo(&#39;'+m[0]+'&#39;,this)"><b>'+(i===0?"&#11088; ":"")+esc(m[0])+'</b><small>'+esc(m[1])+'</small></div>';}).join("")+'</div>';}

var COR_RANK={geral:"#1faa59",bolao:"#e0a008",arena:"#e23744"};
