var CUR_EN="";var CUR_ELENCO=[];var JOGOS_BOLAO=[];
var TQ=[],TIDX=0,TCACHE={},TBUSY=false,TFORCELOGIC=false,TCUR=null;
function startTour(){
 var pend=(JOGOS_BOLAO||[]).filter(function(j){return !j.travado;});
 if(!pend.length){toast("Nenhum jogo aberto nesta rodada (todos travados).",1);return;}
 TQ=pend;TIDX=0;TCACHE={};TFORCELOGIC=false;
 var tc=document.getElementById("tourcard");if(tc)tc.style.setProperty("--rc",COR_ROD[CURROD]||"#14794a");
 document.getElementById("tour").classList.add("show");
 tourShow(0);
}
async function tourFetch(id){
 if(TCACHE[id])return TCACHE[id];
 try{var r=await fetch(BASE+"/jogar/ia/palpitar-jogo",{method:"POST",headers:H(),body:JSON.stringify({jogo:id,soLogica:TFORCELOGIC})});var d=await r.json();if(d&&d.ok){TCACHE[id]=d;return d;}}catch(e){}
 return null;
}
async function tourShow(i){
 if(i>=TQ.length){tourDone();return;}
 TIDX=i;var g=TQ[i];
 document.getElementById("tour-prog").textContent="Jogo "+(i+1)+" de "+TQ.length;
 document.getElementById("tour-flagC").innerHTML=fl(g.casa.iso);
 document.getElementById("tour-flagV").innerHTML=fl(g.visitante.iso);
 document.getElementById("tour-nomeC").textContent=g.casa.pt;
 document.getElementById("tour-nomeV").textContent=g.visitante.pt;
 var rb=document.getElementById("tour-resumo");rb.textContent="analisando o jogo…";var rf=document.getElementById("tour-fonte");if(rf)rf.textContent="";var av0=document.getElementById("tour-aviso");if(av0)av0.style.display="none";
 var ap=document.getElementById("tour-aplicar");if(ap)ap.disabled=true;
 document.getElementById("tpc").value="";document.getElementById("tpv").value="";
 var d=await tourFetch(g.id);
 if(TIDX!==i)return;
 if(!d){rb.textContent="não consegui analisar este jogo.";if(ap)ap.disabled=false;return;}
 var rf=document.getElementById("tour-fonte");
 document.getElementById("tpc").value=d.pc;document.getElementById("tpv").value=d.pv;
 var fonte=d.fonte==="ia"?"sua IA":"lógica";
 rb.textContent=d.resumo||"";
 TCUR=d;if(rf){if(d.fonte==="logica"&&d.passos&&d.passos.length){rf.innerHTML='por '+fonte+'<span class="comocalc" onclick="tourComoCalc()" title="Como a lógica calculou (passo a passo)">&#9432;</span>';}else{rf.textContent="por "+fonte;}rf.title="";}
 var av=document.getElementById("tour-aviso");if(av){if(d.aviso){av.style.display="";av.innerHTML="&#9888;&#65039; "+esc(d.aviso);}else{av.style.display="none";}}
 if(d.aviso&&!TFORCELOGIC)tourQuotaChoice(g.id);
 if(ap)ap.disabled=false;
 if(i+1<TQ.length)tourFetch(TQ[i+1].id);
}
function tourStep(side,dd){var e=document.getElementById(side==="c"?"tpc":"tpv");var v=(parseInt(e.value)||0)+dd;if(v<0)v=0;if(v>99)v=99;e.value=v;}
async function tourApply(){
 if(TBUSY)return;var g=TQ[TIDX];var pc=parseInt(document.getElementById("tpc").value)||0,pv=parseInt(document.getElementById("tpv").value)||0;
 TBUSY=true;var ap=document.getElementById("tour-aplicar");if(ap)ap.disabled=true;
 try{var r=await fetch(BASE+"/jogar/palpite",{method:"POST",headers:H(),body:JSON.stringify({jogo_id:g.id,pc:pc,pv:pv})});var d=await r.json();if(d&&d.ok){g.meu={pc:pc,pv:pv};}else{toast((d&&d.erro)||"erro ao salvar",1);}}catch(e){toast("erro ao salvar",1);}
 TBUSY=false;tourShow(TIDX+1);
}
function tourSkip(){tourShow(TIDX+1);}
function tourPrev(){if(TIDX>0)tourShow(TIDX-1);}
function tourClose(){document.getElementById("tour").classList.remove("show");loadBolao(CURROD);loadDados();}
function tourQuotaChoice(id){modal('<h3>&#9888;&#65039; Sua IA bateu o limite gr&aacute;tis</h3><div class="muted" style="line-height:1.55">O free tier da sua IA atingiu a cota por agora. N&atilde;o &eacute; cobran&ccedil;a &mdash; o limite reseta sozinho (por minuto e por dia). Voc&ecirc; escolhe como continuar:</div><div style="margin-top:10px;font-size:13px;line-height:1.6">&#9203; <b>Aguardar a IA</b>: espere ~1 min e tente de novo (ou troque o modelo em Conectar IA).<br>&#127919; <b>Seguir pela l&oacute;gica</b>: terminamos a rodada na hora pelo nosso sistema de odds (gr&aacute;tis, sem IA).</div>','<button class="btn ghost" onclick="fecha();delete TCACHE['+id+'];tourShow(TIDX);">&#9203; Aguardar e tentar a IA</button><button class="btn" onclick="tourSeguirLogica()">&#127919; Seguir pela l&oacute;gica</button>');}
function tourSeguirLogica(){TFORCELOGIC=true;TCACHE={};fecha();toast("Beleza! Seguindo pela lógica das odds.");tourShow(TIDX);}
function tourComoCalc(){var d=TCUR;if(!d||!d.passos)return;modal('<h3>&#129518; Como a lógica calculou</h3><div class="muted" style="margin-bottom:8px">Sistema determinístico (sem IA), passo a passo &mdash; usando odds, ranking e a forma dos últimos 5 jogos:</div><ol style="margin:0;padding-left:18px;line-height:1.7;font-size:13px">'+d.passos.map(function(p){return "<li>"+esc(p)+"</li>";}).join("")+'</ol>');}
function tourDone(){document.getElementById("tour").classList.remove("show");var n=(TQ||[]).filter(function(j){return !!j.meu;}).length;toast("Tour concluído! "+n+" palpite(s) aplicado(s).");loadBolao(CURROD);loadDados();}

function fmtForma(arr){if(!arr||!arr.length)return '<span class="muted">sem dados</span>';return arr.slice(0,6).map(function(x){if(typeof x==="string")return esc(x);var ad=x.adversario||x.rival||x.vs||x.oponente||"";var g=(x.gols_pro!=null&&x.gols_contra!=null)?(x.gols_pro+"x"+x.gols_contra):(x.placar||"");var t=((ad?ad+" ":"")+g).trim();return esc(t||JSON.stringify(x));}).join(" &middot; ");}
function fmtLineup(l){if(!l||!l.titulares||!l.titulares.length)return '<span class="muted">ainda não divulgada</span>';return (l.confirmada?"Confirmada":"Provável")+" ("+esc(l.formacao||"")+"): "+l.titulares.map(function(t){return esc(t.nome)+(t.posicao?(' <span class="muted">'+esc(t.posicao)+'</span>'):"");}).join(", ");}
function fmtNews(arr){if(!arr||!arr.length)return '<span class="muted">sem notícias recentes</span>';return '<ul style="margin:4px 0 0;padding-left:17px;line-height:1.5">'+arr.slice(0,5).map(function(n){var t=(typeof n==="string")?n:(n.title||n.titulo||"");return t?("<li>"+esc(t)+"</li>"):"";}).join("")+"</ul>";}
function fmtCraques(ex,j){if(!ex||!ex.craques||!ex.craques.length)return '<span class="muted">sem dados</span>';return ex.craques.map(function(cat){function p(pl,iso){if(!pl)return "—";var st=(pl.stats||[]).filter(function(s){return Number(s.valor)>0;}).map(function(s){return s.nome+" "+s.valor;}).join(", ");return '<span class="crqf">'+fl(iso)+'</span>'+esc(pl.nome)+(pl.posicao?(' <span class="muted">'+esc(pl.posicao)+'</span>'):"")+(st?(' <span class="muted">· '+esc(st)+'</span>'):"");}return '<div style="margin:3px 0"><span class="muted" style="font-size:11px;text-transform:uppercase;letter-spacing:.3px">'+esc(cat.categoria)+'</span><br>'+p(cat.casa,j.casa.iso)+'<br>'+p(cat.visitante,j.visitante.iso)+'</div>';}).join("");}
function fmtUlt(arr){if(!arr||!arr.length)return '<span class="muted">sem dados</span>';return arr.map(function(m){return '<span class="u5 u5'+m.res+'">'+m.res+'</span> '+esc(m.adversario)+' <b>'+m.gp+'-'+m.gc+'</b>';}).join("<br>");}
function fmtLideres(arr,j){if(!arr||!arr.length)return "";return arr.filter(function(l){return Number(l.gols)>0;}).map(function(l){var iso=l.lado==="casa"?j.casa.iso:(l.lado==="visitante"?j.visitante.iso:"");var fb=iso?('<span class="crqf">'+fl(iso)+'</span>'):"";return fb+esc(l.nome)+' <b>'+l.gols+'</b> gol'+(Number(l.gols)>1?"s":"")+(l.pos?(' <span class="muted">'+esc(l.pos)+'</span>'):"");}).join("<br>");}
function auditHtml(c){
 var j=c.jogo,od=c.odds,pr=c.probabilidade;
 var h='<h3>&#128270; Dados entregues à sua IA</h3>';
 h+='<div class="muted" style="margin-bottom:10px">'+fl(j.casa.iso)+' <b>'+esc(j.casa.pt)+'</b> &times; <b>'+esc(j.visitante.pt)+'</b> '+fl(j.visitante.iso)+' &mdash; tudo abaixo vai pra IA <b>antes</b> dela escolher o placar. Dados reais, nada inventado.</div>';
 h+='<div class="audsec"><div class="audh">&#127942; Ranking FIFA</div><div>'+esc(j.casa.pt)+': <b>#'+(j.casa.rankFifa||"?")+'</b> &middot; '+esc(j.visitante.pt)+': <b>#'+(j.visitante.rankFifa||"?")+'</b></div></div>';
 var ex=c.extra365;
 if(ex&&ex.venue){h+='<div class="audsec"><div class="audh">&#127967;&#65039; Est&aacute;dio</div><div>'+esc(ex.venue.nome||"")+(ex.venue.capacidade?(' <span class="muted">&middot; '+Number(ex.venue.capacidade).toLocaleString("pt-BR")+' lugares</span>'):"")+'</div></div>';}
 if(ex&&ex.tv&&ex.tv.length){h+='<div class="audsec"><div class="audh">&#128250; Transmiss&atilde;o</div><div>'+ex.tv.map(esc).join(" &middot; ")+'</div></div>';}
 if(ex&&ex.craques&&ex.craques.length){h+='<div class="audsec"><div class="audh">&#11088; Craques em campo</div><div>'+fmtCraques(ex,j)+'</div></div>';}
 if(ex&&ex.casa&&ex.casa.ultimas5){h+='<div class="audsec"><div class="audh">&#9201;&#65039; \u00daltimas 5 &mdash; '+esc(j.casa.pt)+'</div><div>'+fmtUlt(ex.casa.ultimas5)+'</div></div>';}
 if(ex&&ex.visitante&&ex.visitante.ultimas5){h+='<div class="audsec"><div class="audh">&#9201;&#65039; \u00daltimas 5 &mdash; '+esc(j.visitante.pt)+'</div><div>'+fmtUlt(ex.visitante.ultimas5)+'</div></div>';}
 var lid=ex?fmtLideres(ex.golsLideres,j):"";if(lid){h+='<div class="audsec"><div class="audh">&#9917; L\u00edderes de gols</div><div>'+lid+'</div></div>';}
 if(od){h+='<div class="audsec"><div class="audh">&#128176; Odds 1X2 &amp; probabilidade</div><div>'+esc(j.casa.pt)+' <b>'+od.casa+'</b>'+(pr?(' ('+pr.casa+'%)'):'')+' &middot; Empate <b>'+od.empate+'</b>'+(pr?(' ('+pr.empate+'%)'):'')+' &middot; '+esc(j.visitante.pt)+' <b>'+od.fora+'</b>'+(pr?(' ('+pr.fora+'%)'):'')+'<div class="muted" style="font-size:11px">vit\u00f3ria de cada lado / empate &middot; '+esc(od.fonte||"")+'</div></div></div>';}
 h+='<div class="audsec"><div class="audh">&#128203; Escalação '+esc(j.casa.pt)+'</div><div>'+fmtLineup(c.escalacao&&c.escalacao.casa)+'</div></div>';
 h+='<div class="audsec"><div class="audh">&#128203; Escalação '+esc(j.visitante.pt)+'</div><div>'+fmtLineup(c.escalacao&&c.escalacao.visitante)+'</div></div>';
 h+='<div class="audsec"><div class="audh">&#128200; Campanha na Copa 2022 &mdash; '+esc(j.casa.pt)+'</div><div>'+fmtForma(c.forma2022&&c.forma2022.casa)+'</div></div>';
 h+='<div class="audsec"><div class="audh">&#128200; Campanha na Copa 2022 &mdash; '+esc(j.visitante.pt)+'</div><div>'+fmtForma(c.forma2022&&c.forma2022.visitante)+'</div></div>';
 h+='<div class="audsec"><div class="audh">&#128240; Notícias &mdash; '+esc(j.casa.pt)+'</div><div>'+fmtNews(c.noticias&&c.noticias.casa)+'</div></div>';
 h+='<div class="audsec"><div class="audh">&#128240; Notícias &mdash; '+esc(j.visitante.pt)+'</div><div>'+fmtNews(c.noticias&&c.noticias.visitante)+'</div></div>';
 return h;
}
